  static qpdf_result_e fromValue(int value) => switch (value) {
    0 => qpdf_r_ok,
    255 => qpdf_r_no_warn,
    65535 => qpdf_r_success,
    65536 => qpdf_r_bad_parameter,
    2147483392 => qpdf_r_no_warn_mask,
    2147418112 => qpdf_r_success_mask,
    _ => throw ArgumentError('Unknown value for qpdf_result_e: $value'),
  };
}

